import React, { useEffect, useRef, useState } from 'react';
import Navbar from '../components/Navbar';
import MatrixBackground from '../components/MatrixBackground';
import TerminalWindow from '../components/TerminalWindow';
import AmenazaCard from '../components/AmenazaCard';
import TeamSection from '../components/TeamSection';
import Footer from '../components/Footer';
import { useTema } from '../context/TemaContext';

const Ciberseguridad = () => {
  const { colorFondo, tamañoLetra, colores } = useTema();
  const [counters, setCounters] = useState([
    { icon: 'fa-virus', target: 847, label: 'Amenazas Detectadas Hoy', current: 0 },
    { icon: 'fa-shield-alt', target: 156, label: 'Ataques Bloqueados', current: 0 },
    { icon: 'fa-lock', target: 99.9, label: '% de Protección', current: 0 }
  ]);
  const countersRef = useRef(null);
  const animatedRef = useRef(false);

  const appStyle = {
    background: colores[colorFondo] || colores.oscuro,
    fontSize: tamañoLetra === 'medium' ? '16px' :
              tamañoLetra === 'pequeño' ? '12px' :
              tamañoLetra === 'grande' ? '20px' : '25px',
    minHeight: '100vh',
    transition: 'all 0.4s ease'
  };

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) entry.target.classList.add('visible');
        });
      },
      { threshold: 0.1 }
    );
    document.querySelectorAll('.servicio-card, .galeria-item, .ceo-card').forEach((el) => {
      el.classList.add('scroll-hidden');
      observer.observe(el);
    });

    const handleScroll = () => {
      const navbar = document.querySelector('.navbar');
      if (!navbar) return;
      if (window.scrollY > 50) navbar.classList.add('scrolled');
      else navbar.classList.remove('scrolled');
    };
    window.addEventListener('scroll', handleScroll);

    return () => {
      observer.disconnect();
      window.removeEventListener('scroll', handleScroll);
    };
  }, []);

  useEffect(() => {
    const counterObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting && !animatedRef.current) {
            animatedRef.current = true;
            counters.forEach((c, idx) => {
              const duration = 2000;
              const increment = c.target / (duration / 16);
              let current = 0;
              const updateCounter = () => {
                current += increment;
                if (current < c.target) {
                  setCounters((prev) => {
                    const copy = [...prev];
                    copy[idx] = { ...copy[idx], current: c.target % 1 !== 0 ? parseFloat(current.toFixed(1)) : Math.floor(current) };
                    return copy;
                  });
                  requestAnimationFrame(updateCounter);
                } else {
                  setCounters((prev) => {
                    const copy = [...prev];
                    copy[idx] = { ...copy[idx], current: c.target };
                    return copy;
                  });
                }
              };
              updateCounter();
            });
          }
        });
      },
      { threshold: 0.3 }
    );

    if (countersRef.current) counterObserver.observe(countersRef.current);
    return () => counterObserver.disconnect();
  }, []);

  const amenazas = [
    {
      icon: 'fa-bug', iconClass: 'malware', title: 'Malware',
      desc: 'Software malicioso diseñado para dañar, infiltrarse o dañar sistemas informáticos.',
      items: ['Virus', 'Troyanos', 'Ransomware', 'Spyware'], nivel: 'Alto', nivelClass: 'alto'
    },
    {
      icon: 'fa-fishing', iconClass: 'phishing', title: 'Phishing',
      desc: 'Técnicas de engaño para obtener información confidencial haciéndose pasar por entidades de confianza.',
      items: ['Spear Phishing', 'Whaling', 'Smishing', 'Vishing'], nivel: 'Alto', nivelClass: 'alto'
    },
    {
      icon: 'fa-network-wired', iconClass: 'ddos', title: 'DDoS',
      desc: 'Ataques de denegación de servicio distribuidos que saturan sistemas para hacerlos inaccesibles.',
      items: ['Volumétricos', 'Protocolo', 'Aplicación', 'Amplificación'], nivel: 'Medio', nivelClass: 'medio'
    },
    {
      icon: 'fa-database', iconClass: 'sql', title: 'Inyección SQL',
      desc: 'Aprovechamiento de vulnerabilidades en bases de datos mediante código malicioso SQL.',
      items: ['SQLi Clásico', 'Blind SQLi', 'Union Based', 'Error Based'], nivel: 'Crítico', nivelClass: 'critico'
    },
    {
      icon: 'fa-code', iconClass: 'xss', title: 'XSS',
      desc: 'Cross-Site Scripting permite inyectar scripts maliciosos en páginas web vistas por otros usuarios.',
      items: ['Reflejado', 'Almacenado', 'DOM Based', 'Self-XSS'], nivel: 'Medio', nivelClass: 'medio'
    },
    {
      icon: 'fa-user-secret', iconClass: 'mitm', title: 'Man in the Middle',
      desc: 'Ataques donde el atacante intercepta y posiblemente altera la comunicación entre dos partes.',
      items: ['ARP Spoofing', 'DNS Spoofing', 'SSL Stripping', 'Session Hijacking'], nivel: 'Alto', nivelClass: 'alto'
    }
  ];

  const equipos = [
    {
      id: 'red-team', badgeIcon: 'fa-fire', badgeLabel: 'OFENSIVO', sectionClass: 'red-section',
      title: 'Red Team Operations',
      desc: 'Simulación de ataques reales para identificar vulnerabilidades antes que los ciberdelincuentes. Nuestro equipo rojo utiliza las mismas técnicas que los hackers maliciosos, pero éticamente y con tu permiso.',
      services: [
        { icon: 'fa-search', name: 'Reconocimiento', desc: 'Recopilación de información sobre el objetivo' },
        { icon: 'fa-crosshairs', name: 'Explotación', desc: 'Aprovechamiento de vulnerabilidades encontradas' },
        { icon: 'fa-user-ninja', name: 'Post-Explotación', desc: 'Movimiento lateral y persistencia' },
        { icon: 'fa-file-alt', name: 'Reporting', desc: 'Documentación detallada de hallazgos' }
      ],
      tools: ['Metasploit', 'Cobalt Strike', 'Burp Suite', 'Nmap', 'BloodHound']
    },
    {
      id: 'blue-team', badgeIcon: 'fa-shield-alt', badgeLabel: 'DEFENSIVO', sectionClass: 'blue-section',
      title: 'Blue Team Defense',
      desc: 'Protección continua y respuesta a incidentes. Nuestro equipo azul se encarga de defender tu infraestructura, detectar amenazas y responder ante incidentes de seguridad.',
      services: [
        { icon: 'fa-eye', name: 'Monitoreo 24/7', desc: 'Vigilancia continua de sistemas' },
        { icon: 'fa-search-dollar', name: 'Threat Hunting', desc: 'Búsqueda proactiva de amenazas' },
        { icon: 'fa-first-aid', name: 'Incident Response', desc: 'Respuesta y remediación de incidentes' },
        { icon: 'fa-clipboard-check', name: 'Hardening', desc: 'Fortalecimiento de sistemas' }
      ],
      tools: ['Splunk', 'Wazuh', 'Suricata', 'YARA', 'Velociraptor']
    },
    {
      id: 'purple-team', badgeIcon: 'fa-handshake', badgeLabel: 'COLABORATIVO', sectionClass: 'purple-section',
      title: 'Purple Team Integration',
      desc: 'La sinergia perfecta entre ataque y defensa. El equipo púrpura combina las capacidades de Red y Blue Team para maximizar la efectividad de la seguridad organizacional.',
      services: [
        { icon: 'fa-exchange-alt', name: 'Simulacros', desc: 'Ejercicios controlados de ataque/defensa' },
        { icon: 'fa-chart-line', name: 'Métricas', desc: 'Medición de efectividad defensiva' },
        { icon: 'fa-sync', name: 'Feedback Loop', desc: 'Mejora continua bidireccional' },
        { icon: 'fa-graduation-cap', name: 'Training', desc: 'Capacitación conjunta de equipos' }
      ],
      tools: ['Atomic Red Team', 'MITRE ATT&CK', 'Caldera', 'Prelude', 'Vectra']
    }
  ];

  const consultoriaItems = [
    { icon: 'fa-check-square', title: 'ISO 27001', desc: 'Implementación y auditoría de Sistemas de Gestión de Seguridad de la Información' },
    { icon: 'fa-balance-scale', title: 'GDPR / Protección de Datos', desc: 'Cumplimiento normativo en protección de datos personales' },
    { icon: 'fa-shield-virus', title: 'Pentesting', desc: 'Pruebas de penetración de redes, aplicaciones y sistemas' },
    { icon: 'fa-search', title: 'Auditoría de Código', desc: 'Revisión de seguridad en desarrollo de software' }
  ];

  const recursos = [
    {
      icon: 'fa-book', title: 'Documentación',
      links: ['OWASP Top 10', 'MITRE ATT&CK Framework', 'NIST Cybersecurity Framework', 'CIS Controls']
    },
    {
      icon: 'fa-laptop-code', title: 'Laboratorios',
      links: ['Hack The Box', 'TryHackMe', 'VulnHub', 'OverTheWire']
    },
    {
      icon: 'fa-certificate', title: 'Certificaciones',
      links: ['CEH - Certified Ethical Hacker', 'OSCP - Offensive Security', 'CISSP - ISC2', 'CompTIA Security+']
    },
    {
      icon: 'fa-users', title: 'Comunidad',
      links: ['Foros de Seguridad', 'Grupos de Discord', 'Meetups Locales', 'CTF Competitions']
    }
  ];

  const herramientas = [
    { icon: 'fa-terminal', title: 'Escaneo y Enumeración', tags: ['Nmap', 'Masscan', 'Rustscan', 'Recon-ng'] },
    { icon: 'fa-bug', title: 'Exploit y Pentesting', tags: ['Metasploit', 'Cobalt Strike', 'Sliver', 'Empire'] },
    { icon: 'fa-search', title: 'Análisis Web', tags: ['Burp Suite', 'OWASP ZAP', 'SQLMap', 'Nikto'] },
    { icon: 'fa-eye', title: 'Monitoreo', tags: ['Splunk', 'Wazuh', 'Suricata', 'Zeek'] }
  ];

  return (
    <div style={appStyle} className="ciberseguridad-page">
      <MatrixBackground />
      <Navbar dark />

      <header className="cyber-header">
        <div className="cyber-header-content">
          <TerminalWindow />
          <h1>Portal de Ciberseguridad</h1>
          <p className="subtitle">Conocimiento, herramientas y recursos para la defensa digital</p>
        </div>
        <div className="cyber-stats" ref={countersRef}>
          {counters.map((c, i) => (
            <div className="cyber-stat" key={i}>
              <i className={`fas ${c.icon}`}></i>
              <span className="counter">{c.current}</span>
              <p>{c.label}</p>
            </div>
          ))}
        </div>
      </header>

      <section id="amenazas" className="amenazas-section">
        <div className="container">
          <div className="section-header dark">
            <i className="fas fa-exclamation-triangle"></i>
            <h2>Tipos de Amenazas</h2>
            <p>Conoce los principales vectores de ataque en el ciberespacio</p>
          </div>
          <div className="amenazas-grid">
            {amenazas.map((a, i) => (
              <AmenazaCard key={i} amenaza={a} />
            ))}
          </div>
        </div>
      </section>

      {equipos.map((team, i) => (
        <TeamSection key={i} team={team} />
      ))}

      <section id="consultoria" className="consultoria-section">
        <div className="container">
          <div className="section-header dark">
            <i className="fas fa-clipboard-list"></i>
            <h2>Consultoría y Cumplimiento</h2>
            <p>Auditorías, certificaciones y gestión de riesgos</p>
          </div>
          <div className="consultoria-grid">
            {consultoriaItems.map((item, i) => (
              <div className="consultoria-item" key={i}>
                <i className={`fas ${item.icon}`}></i>
                <h3>{item.title}</h3>
                <p>{item.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      <section id="recursos" className="recursos-section">
        <div className="container">
          <div className="section-header dark">
            <i className="fas fa-graduation-cap"></i>
            <h2>Recursos de Aprendizaje</h2>
            <p>Material educativo para profesionales de seguridad</p>
          </div>
          <div className="recursos-grid">
            {recursos.map((recurso, i) => (
              <div className="recurso-card" key={i}>
                <div className="recurso-icon">
                  <i className={`fas ${recurso.icon}`}></i>
                </div>
                <h3>{recurso.title}</h3>
                <ul>
                  {recurso.links.map((link, j) => (
                    <li key={j}><a href="#">{link}</a></li>
                  ))}
                </ul>
              </div>
            ))}
          </div>
        </div>
      </section>

      <section id="herramientas" className="herramientas-section">
        <div className="container">
          <div className="section-header dark">
            <i className="fas fa-toolbox"></i>
            <h2>Kit de Herramientas Esenciales</h2>
            <p>Software profesional para operaciones de seguridad</p>
          </div>
          <div className="herramientas-categorias">
            {herramientas.map((cat, i) => (
              <div className="herramienta-cat" key={i}>
                <h4><i className={`fas ${cat.icon}`}></i> {cat.title}</h4>
                <div className="herramientas-tags">
                  {cat.tags.map((tag, j) => (
                    <span className="herramienta-tag" key={j}>{tag}</span>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      <section id="contacto" className="contacto contacto-dark">
        <div className="container">
          <div className="section-header dark">
            <i className="fas fa-headset"></i>
            <h2>¿Necesitas ayuda urgente?</h2>
            <p>Contáctanos para una consulta de seguridad inmediata</p>
          </div>
          <div className="emergency-contact">
            <div className="emergency-card">
              <i className="fas fa-phone-volume"></i>
              <h3>Línea de Emergencia</h3>
              <p className="emergency-number">+591 12345678</p>
              <p>Disponible 24/7 para incidentes críticos</p>
            </div>
          </div>
        </div>
      </section>

      <Footer cyber />
    </div>
  );
};

export default Ciberseguridad;
